const token = $json.access_token;
const prefix = $('Config').first().json['VPN_GROUP_PREFIX'];
let script = `
const https = require('https');
const fs = require('fs');

const TOKEN = '__TOKEN__';
const PREFIX = '__PREFIX__';
const OUTPUT = '/tmp/azure_vpn_groups_report.json';

function graphGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, { headers: { 'Authorization': 'Bearer ' + TOKEN } }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        try { resolve(JSON.parse(d)); }
        catch(e) { reject(new Error('Parse error')); }
      });
    }).on('error', reject);
  });
}

async function paginate(url) {
  const results = [];
  while (url) {
    const d = await graphGet(url);
    if (d.error) { console.error('API Error:', d.error.message); break; }
    results.push(...(d.value || []));
    url = d['@odata.nextLink'] || null;
    if (results.length % 500 === 0) console.log('  ...' + results.length);
  }
  return results;
}

async function main() {
  console.log('Step 1: Fetching ALL enabled users with signInActivity...');
  const allUsers = await paginate(
    'https://graph.microsoft.com/beta/users?$filter=accountEnabled%20eq%20true' +
    '&$select=id,userPrincipalName,createdDateTime,signInActivity' +
    '&$top=100'
  );
  console.log('Total enabled users: ' + allUsers.length);

  const userMap = new Map();
  allUsers.forEach(u => {
    const sia = u.signInActivity || {};
    const lastI = sia.lastSignInDateTime || null;
    const lastNI = sia.lastNonInteractiveSignInDateTime || null;

    let latest = null;
    if (lastI && lastNI) latest = new Date(lastI) > new Date(lastNI) ? lastI : lastNI;
    else latest = lastI || lastNI;

    userMap.set(u.id, {
      userPrincipalName: u.userPrincipalName || '',
      createdDate: (u.createdDateTime || '').substring(0, 10),
      lastLogin: latest ? latest.substring(0, 19).replace('T', ' ') : 'Nunca'
    });
  });
  console.log('User map created with ' + userMap.size + ' entries');

  console.log('Step 2: Fetching VPN groups with prefix: ' + PREFIX);
  const groups = await paginate(
    'https://graph.microsoft.com/v1.0/groups?$filter=startswith(displayName,\\'' + PREFIX + '\\')' +
    '&$select=id,displayName,description&$top=100'
  );
  groups.sort((a, b) => (a.displayName || '').localeCompare(b.displayName || ''));
  console.log('Found ' + groups.length + ' VPN groups');

  const report = [];
  for (const g of groups) {
    console.log('Processing: ' + g.displayName);
    const membersRaw = await paginate(
      'https://graph.microsoft.com/v1.0/groups/' + g.id + '/members?$select=id,userPrincipalName,displayName&$top=100'
    );
    const memberIds = membersRaw.filter(m => m.userPrincipalName);
    console.log('  Members: ' + memberIds.length);

    const members = [];
    for (const m of memberIds) {
      const userData = userMap.get(m.id);
      if (userData) {
        members.push(userData);
      } else {
        members.push({
          userPrincipalName: m.userPrincipalName || m.displayName || m.id,
          createdDate: 'N/D',
          lastLogin: 'N/D'
        });
      }
    }
    members.sort((a, b) => a.userPrincipalName.localeCompare(b.userPrincipalName));
    report.push({
      groupName: g.displayName,
      groupId: g.id,
      description: g.description || '',
      memberCount: members.length,
      members: members
    });
    console.log('  Completed: ' + g.displayName + ' (' + members.length + ' members)');
  }

  report.sort((a, b) => a.groupName.localeCompare(b.groupName));
  fs.writeFileSync(OUTPUT, JSON.stringify(report));
  const totalMembers = report.reduce((s, g) => s + g.memberCount, 0);
  console.log('TOTAL_GROUPS: ' + report.length);
  console.log('TOTAL_MEMBERS: ' + totalMembers);
  console.log('DONE');
}
main().catch(e => { console.error('FATAL:', e); process.exit(1); });
`;
script = script.replace('__TOKEN__', token);
script = script.replace('__PREFIX__', prefix);
const b64 = Buffer.from(script).toString('base64');
return [{ json: { scriptB64: b64 } }];

let script = `
const fs = require('fs');
const zlib = require('zlib');

const report = JSON.parse(fs.readFileSync('/tmp/azure_vpn_groups_report.json', 'utf8'));
console.log('Building multi-sheet Excel for ' + report.length + ' VPN groups...');

function esc(s) {
  if (s == null) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\\\\\\\\"/g,'&quot;');
}

function sanitizeSheetName(name) {
  let sn = String(name);
  let out = '';
  for (let i = 0; i < sn.length && out.length < 31; i++) {
    let c = sn[i];
    if ('[]*?/:'.includes(c)) c = '_';
    out += c;
  }
  return out;
}

function col(c) { let s=''; while(c>=0){s=String.fromCharCode(65+(c%26))+s;c=Math.floor(c/26)-1;} return s; }

const ssMap = new Map();
const ssList = [];
function addSS(s) { const k = String(s); if (!ssMap.has(k)) { ssMap.set(k, ssList.length); ssList.push(k); } return ssMap.get(k); }

const summaryHeaders = ['Grupo', 'Num Miembros', 'Responsable'];
const detailHeaders = ['UserPrincipalName', 'Fecha Creacion Usuario', 'Fecha Last Login'];
summaryHeaders.forEach(addSS);
detailHeaders.forEach(addSS);
addSS('TOTAL');
report.forEach(g => {
  addSS(g.groupName); addSS(String(g.memberCount)); addSS('');
  g.members.forEach(m => { addSS(m.userPrincipalName); addSS(m.createdDate); addSS(m.lastLogin); });
});
const totalMembers = report.reduce((s,g) => s + g.memberCount, 0);
addSS(String(totalMembers));

const sheets = [];

// Sheet 1: Resumen
let sd1 = '<row r="1">';
summaryHeaders.forEach((h, i) => {
  sd1 += '<c r="' + col(i) + '1" t="s" s="1"><v>' + addSS(h) + '</v></c>';
});
sd1 += '</row>';
report.forEach((g, ri) => {
  const rn = ri + 2;
  sd1 += '<row r="' + rn + '">';
  sd1 += '<c r="A' + rn + '" t="s" s="0"><v>' + addSS(g.groupName) + '</v></c>';
  sd1 += '<c r="B' + rn + '" t="s" s="3"><v>' + addSS(String(g.memberCount)) + '</v></c>';
  sd1 += '<c r="C' + rn + '" t="s" s="0"><v>' + addSS('') + '</v></c>';
  sd1 += '</row>';
});
const totalRow = report.length + 2;
sd1 += '<row r="' + totalRow + '">';
sd1 += '<c r="A' + totalRow + '" t="s" s="1"><v>' + addSS('TOTAL') + '</v></c>';
sd1 += '<c r="B' + totalRow + '" t="s" s="4"><v>' + addSS(String(totalMembers)) + '</v></c>';
sd1 += '<c r="C' + totalRow + '" t="s" s="0"><v>' + addSS('') + '</v></c>';
sd1 += '</row>';

const sheet1xml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
  + '<cols><col min="1" max="1" width="45" customWidth="1"/><col min="2" max="2" width="16" customWidth="1"/>'
  + '<col min="3" max="3" width="30" customWidth="1"/></cols>'
  + '<sheetData>' + sd1 + '</sheetData>'
  + '<autoFilter ref="A1:C' + (report.length + 1) + '"/></worksheet>';
sheets.push({ name: 'Resumen', xml: sheet1xml });

// Detail sheets
report.forEach(g => {
  let sd = '<row r="1">';
  detailHeaders.forEach((h, i) => {
    sd += '<c r="' + col(i) + '1" t="s" s="1"><v>' + addSS(h) + '</v></c>';
  });
  sd += '</row>';
  g.members.forEach((m, ri) => {
    const rn = ri + 2;
    sd += '<row r="' + rn + '">';
    sd += '<c r="A' + rn + '" t="s" s="0"><v>' + addSS(m.userPrincipalName) + '</v></c>';
    sd += '<c r="B' + rn + '" t="s" s="0"><v>' + addSS(m.createdDate) + '</v></c>';
    let ls = '0';
    if (m.lastLogin === 'Nunca') {
      ls = '2';
    } else if (m.lastLogin !== 'N/D' && m.lastLogin !== 'Error') {
      try {
        const loginDate = new Date(m.lastLogin.replace(' ', 'T'));
        const now = new Date();
        const daysDiff = Math.floor((now - loginDate) / 86400000);
        if (daysDiff > 90) ls = '2';
      } catch(e) {}
    }
    sd += '<c r="C' + rn + '" t="s" s="' + ls + '"><v>' + addSS(m.lastLogin) + '</v></c>';
    sd += '</row>';
  });
  const sx = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
    + '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
    + '<cols><col min="1" max="1" width="45" customWidth="1"/><col min="2" max="2" width="22" customWidth="1"/>'
    + '<col min="3" max="3" width="22" customWidth="1"/></cols>'
    + '<sheetData>' + sd + '</sheetData>'
    + '<autoFilter ref="A1:C' + (g.members.length + 1) + '"/></worksheet>';
  sheets.push({ name: sanitizeSheetName(g.groupName), xml: sx });
});

// Shared strings
const ssXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="'
  + ssList.length + '" uniqueCount="' + ssList.length + '">'
  + ssList.map(s => '<si><t>' + esc(s) + '</t></si>').join('') + '</sst>';

// Styles
const stylesXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">'
  + '<fonts count="2"><font><sz val="11"/><name val="Calibri"/></font>'
  + '<font><b/><sz val="11"/><color rgb="FFFFFFFF"/><name val="Calibri"/></font></fonts>'
  + '<fills count="4"><fill><patternFill patternType="none"/></fill>'
  + '<fill><patternFill patternType="gray125"/></fill>'
  + '<fill><patternFill patternType="solid"><fgColor rgb="FF2F5496"/></patternFill></fill>'
  + '<fill><patternFill patternType="solid"><fgColor rgb="FFFFC7CE"/></patternFill></fill></fills>'
  + '<borders count="1"><border><left/><right/><top/><bottom/><diagonal/></border></borders>'
  + '<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>'
  + '<cellXfs count="5">'
  + '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"/>'
  + '<xf numFmtId="0" fontId="1" fillId="2" borderId="0" xfId="0" applyFont="1" applyFill="1" applyAlignment="1"><alignment horizontal="center" wrapText="1"/></xf>'
  + '<xf numFmtId="0" fontId="0" fillId="3" borderId="0" xfId="0" applyFill="1"><alignment horizontal="center"/></xf>'
  + '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0" applyAlignment="1"><alignment horizontal="center"/></xf>'
  + '<xf numFmtId="0" fontId="1" fillId="2" borderId="0" xfId="0" applyFont="1" applyFill="1" applyAlignment="1"><alignment horizontal="center"/></xf>'
  + '</cellXfs></styleSheet>';

// Workbook
let sheetsTag = '';
sheets.forEach((s, i) => {
  sheetsTag += '<sheet name="' + esc(s.name) + '" sheetId="' + (i+1) + '" r:id="rId' + (i+1) + '"/>';
});
const wbXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
  + '<sheets>' + sheetsTag + '</sheets></workbook>';

// Workbook rels
let wbrRels = '';
sheets.forEach((s, i) => {
  wbrRels += '<Relationship Id="rId' + (i+1) + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet' + (i+1) + '.xml"/>';
});
wbrRels += '<Relationship Id="rId' + (sheets.length+1) + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" Target="sharedStrings.xml"/>';
wbrRels += '<Relationship Id="rId' + (sheets.length+2) + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>';
const wbrXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' + wbrRels + '</Relationships>';

// Content Types
let overrides = '';
sheets.forEach((s, i) => {
  overrides += '<Override PartName="/xl/worksheets/sheet' + (i+1) + '.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>';
});
const ctXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">'
  + '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>'
  + '<Default Extension="xml" ContentType="application/xml"/>'
  + '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>'
  + overrides
  + '<Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>'
  + '<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>'
  + '</Types>';

const relsXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>'
  + '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
  + '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/></Relationships>';

// ZIP builder
function crc32(buf) {
  let table = crc32.table;
  if (!table) {
    table = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
      let c = i;
      for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c;
    }
    crc32.table = table;
  }
  let crc = 0xFFFFFFFF;
  for (let i = 0; i < buf.length; i++) crc = table[(crc ^ buf[i]) & 0xFF] ^ (crc >>> 8);
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

function buildZip(entries) {
  const localHeaders = [];
  const centralHeaders = [];
  let offset = 0;

  for (const entry of entries) {
    const nameB = Buffer.from(entry.name, 'utf8');
    const raw = entry.data;
    const compressed = zlib.deflateRawSync(raw);
    const cv = crc32(raw);

    const lh = Buffer.alloc(30 + nameB.length);
    lh.writeUInt32LE(0x04034b50, 0);
    lh.writeUInt16LE(20, 4);
    lh.writeUInt16LE(0, 6);
    lh.writeUInt16LE(8, 8);
    lh.writeUInt16LE(0, 10);
    lh.writeUInt16LE(0, 12);
    lh.writeUInt32LE(cv, 14);
    lh.writeUInt32LE(compressed.length, 18);
    lh.writeUInt32LE(raw.length, 22);
    lh.writeUInt16LE(nameB.length, 26);
    lh.writeUInt16LE(0, 28);
    nameB.copy(lh, 30);

    localHeaders.push(Buffer.concat([lh, compressed]));

    const ch = Buffer.alloc(46 + nameB.length);
    ch.writeUInt32LE(0x02014b50, 0);
    ch.writeUInt16LE(20, 4);
    ch.writeUInt16LE(20, 6);
    ch.writeUInt16LE(0, 8);
    ch.writeUInt16LE(8, 10);
    ch.writeUInt16LE(0, 12);
    ch.writeUInt16LE(0, 14);
    ch.writeUInt32LE(cv, 16);
    ch.writeUInt32LE(compressed.length, 20);
    ch.writeUInt32LE(raw.length, 24);
    ch.writeUInt16LE(nameB.length, 28);
    ch.writeUInt16LE(0, 30);
    ch.writeUInt16LE(0, 32);
    ch.writeUInt16LE(0, 34);
    ch.writeUInt16LE(0, 36);
    ch.writeUInt32LE(0, 38);
    ch.writeUInt32LE(offset, 42);
    nameB.copy(ch, 46);

    centralHeaders.push(ch);
    offset += lh.length + compressed.length;
  }

  const centralDir = Buffer.concat(centralHeaders);
  const centralDirOffset = offset;

  const eocd = Buffer.alloc(22);
  eocd.writeUInt32LE(0x06054b50, 0);
  eocd.writeUInt16LE(0, 4);
  eocd.writeUInt16LE(0, 6);
  eocd.writeUInt16LE(entries.length, 8);
  eocd.writeUInt16LE(entries.length, 10);
  eocd.writeUInt32LE(centralDir.length, 12);
  eocd.writeUInt32LE(centralDirOffset, 16);
  eocd.writeUInt16LE(0, 20);

  return Buffer.concat([...localHeaders, centralDir, eocd]);
}

const zipEntries = [
  { name: '[Content_Types].xml', data: Buffer.from(ctXml, 'utf8') },
  { name: '_rels/.rels', data: Buffer.from(relsXml, 'utf8') },
  { name: 'xl/workbook.xml', data: Buffer.from(wbXml, 'utf8') },
  { name: 'xl/_rels/workbook.xml.rels', data: Buffer.from(wbrXml, 'utf8') },
  { name: 'xl/sharedStrings.xml', data: Buffer.from(ssXml, 'utf8') },
  { name: 'xl/styles.xml', data: Buffer.from(stylesXml, 'utf8') },
];
sheets.forEach((s, i) => {
  zipEntries.push({ name: 'xl/worksheets/sheet' + (i+1) + '.xml', data: Buffer.from(s.xml, 'utf8') });
});

const zipBuf = buildZip(zipEntries);
fs.writeFileSync('/tmp/grupos_vpn_reporte.xlsx', zipBuf);
console.log('Excel: ' + zipBuf.length + ' bytes, ' + sheets.length + ' sheets');
console.log('DONE');
`;
const b64 = Buffer.from(script).toString('base64');
return [{ json: { scriptB64: b64 } }];

const xlsxB64 = $json.stdout.trim();
const emailTo = $('Config').first().json['EMAIL_TO'];
const emailFrom = $('Config').first().json['EMAIL_FROM'];
const now = new Date().toISOString().substring(0, 10);
const po = $('Fetch VPN Groups').first().json.stdout || '';
const totalGroups = (po.match(/TOTAL_GROUPS: (\d+)/) || [])[1] || '?';
const totalMembers = (po.match(/TOTAL_MEMBERS: (\d+)/) || [])[1] || '?';
const subject = 'Reporte Grupos VPN (AZ_VPN) - ' + now;
const html = '<html><body style="font-family:Arial,sans-serif;font-size:14px;color:#333">'
  + '<h2 style="color:#2F5496">Reporte de Grupos VPN (AZ_VPN)</h2>'
  + '<p>Se adjunta el reporte de los grupos de acceso VPN en Azure AD (prefijo <b>AZ_VPN</b>).</p>'
  + '<table style="border-collapse:collapse;margin:16px 0">'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Total grupos VPN:</td><td>' + totalGroups + '</td></tr>'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Total miembros (suma):</td><td>' + totalMembers + '</td></tr>'
  + '</table>'
  + '<p><b>Contenido del Excel:</b></p>'
  + '<ul>'
  + '<li><b>Pesta\u00f1a Resumen</b>: Listado de grupos con n\u00ba de miembros y columna de responsable</li>'
  + '<li><b>Pesta\u00f1as por grupo</b>: Detalle de usuarios con UserPrincipalName, Fecha creaci\u00f3n y \u00daltimo login</li>'
  + '</ul>'
  + '<p>Fecha: <b>' + now + '</b></p>'
  + '<p style="font-size:12px;color:#999;margin-top:24px">Generado autom\u00e1ticamente por n8n.</p>'
  + '</body></html>';
const fileName = 'Grupos_VPN_Reporte_' + now + '.xlsx';
return [{
  json: { subject, html, emailTo, emailFrom, fileName },
  binary: {
    attachment: {
      data: xlsxB64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: fileName
    }
  }
}];
